interface.definition:
a!localVariables(
  local!activeScreen: "HOME",
  local!selectedLivestream,
  local!currentTime: a!refreshVariable(
    value: now(),
    refreshAlways: true,
    refreshInterval: 0.5
  ),
  local!tvShows: {
    #"SYSTEM_SYSRULES_forEach"(
      items: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1065030"(),
      expression: a!map(
        id: fv!index,
        image: fv!item
      )
    )
  },
  local!livestreams: {
    a!map(
      id: 1,
      name: "ARD",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1065739",
      url: "https://www.ardmediathek.de/live"
    ),
    a!map(
      id: 2,
      name: "ZDF",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1065733",
      url: "https://www.zdf.de/live-tv"
    ),
    a!map(
      id: 3,
      name: "ARTE",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1065727",
      url: "https://www.arte.tv/de/live/"
    )
  },

  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_cardLayout"(
      contents: {
        #"SYSTEM_SYSRULES_sideBySideLayout"(
          items: {
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  "   ",
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "reply",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: null,
                      saveInto: {
                        ri!function,
                        a!save(
                          target: local!selectedLivestream,
                          value: null
                        )
                      }
                    ),
                    linkStyle: "STANDALONE",
                    color: "#000000",
                    size: "LARGE_PLUS"
                  )
                }
              )
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextItem_v1"(
                    text: "MEDIEN",
                    size: "LARGE"
                  )
                }
              ),
              width: "MINIMIZE"
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "television",
                    color: "",
                    size: "EXTRA_LARGE"
                  )
                },
                align: "RIGHT"
              ),
              width: "MINIMIZE"
            )
          },
          alignVertical: "MIDDLE"
        )
      },
      style: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1],
      showBorder: false,
      marginBelow: "MORE"
    ),
    contents: {
      #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {

          /*Navigation Element Left*/
          #"SYSTEM_SYSRULES_columnLayout"(
            width: "1X",
            contents: {
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                accessibilityText: "Navigiere zur Startseite Medien",
                marginAbove: "EVEN_MORE",
                align: "CENTER",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "home",
                    color: if(
                      local!activeScreen = "HOME",
                      "STANDARD",
                      #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1]
                    ),
                    size: "LARGE_PLUS",
                    caption: "Startseite Medien",
                    linkStyle: "STANDALONE",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: "HOME",
                      saveInto: {
                        local!activeScreen,
                        a!save(
                          target: local!selectedLivestream,
                          value: null
                        )
                      }
                    )
                  )
                }
              ),
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                accessibilityText: "Navigiere zu Live TV",
                marginAbove: "MORE",
                align: "CENTER",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "tv",
                    color: if(
                      local!activeScreen = "LIVE",
                      "STANDARD",
                      #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1]
                    ),
                    size: "LARGE_PLUS",
                    caption: "Live TV",
                    linkStyle: "STANDALONE",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: "LIVE",
                      saveInto: {
                        local!activeScreen,
                        a!save(
                          target: local!selectedLivestream,
                          value: null
                        )
                      }
                    )
                  )
                }
              ),
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                accessibilityText: "Navigiere zur Videothek",
                marginAbove: "MORE",
                align: "CENTER",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "stream",
                    color: if(
                      local!activeScreen = "SHOWS",
                      "STANDARD",
                      #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1]
                    ),
                    size: "LARGE_PLUS",
                    caption: "Videothek",
                    linkStyle: "STANDALONE",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: "SHOWS",
                      saveInto: {
                        local!activeScreen,
                        a!save(
                          target: local!selectedLivestream,
                          value: null
                        )
                      }
                    )
                  )
                }
              )
            }
          ),

          /*Screen: HOME*/
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: local!activeScreen = "HOME",
            width: "10X",
            contents: {
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: "Jetzt weiterschauen",
                  size: "LARGE",
                  style: "STRONG",
                  color: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1]
                )
              ),
              #"SYSTEM_SYSRULES_cardGroupLayout"(
                fillContainer: true,
                cardWidth: "EXTRA_NARROW",
                cards: {
                  #"SYSTEM_SYSRULES_forEach"(
                    items: index(local!tvShows, {1,2,3}, null),
                    expression: #"SYSTEM_SYSRULES_cardLayout"(
                      marginBelow: "LESS",
                      style: "TRANSPARENT",
                      showBorder: false,
                      showShadow: false,
                      height: "AUTO",
                      shape: "ROUNDED",
                      padding: "NONE",
                      link: #"SYSTEM_SYSRULES_dynamicLink"(),
                      contents: #"SYSTEM_SYSRULES_imageField_v1"(
                        labelPosition: "COLLAPSED",
                        size: "FIT",
                        align: "CENTER",
                        images: #"SYSTEM_SYSRULES_documentImage"(
                          document: fv!item.image
                        )
                      )
                    )
                  )
                }
              ),
              #"SYSTEM_SYSRULES_richTextDisplayField"(
                marginAbove: "MORE",
                value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: "Empfehlungen für Dich",
                  size: "LARGE",
                  style: "STRONG",
                  color: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[1]
                )
              ),
              #"SYSTEM_SYSRULES_cardGroupLayout"(
                fillContainer: true,
                cardWidth: "EXTRA_NARROW",
                cards: {
                  #"SYSTEM_SYSRULES_forEach"(
                    items: index(local!tvShows, {11,8,6}, null),
                    expression: #"SYSTEM_SYSRULES_cardLayout"(
                      marginBelow: "LESS",
                      style: "TRANSPARENT",
                      showBorder: false,
                      showShadow: false,
                      height: "AUTO",
                      shape: "ROUNDED",
                      padding: "NONE",
                      link: #"SYSTEM_SYSRULES_dynamicLink"(),
                      contents: #"SYSTEM_SYSRULES_imageField_v1"(
                        labelPosition: "COLLAPSED",
                        size: "FIT",
                        align: "CENTER",
                        images: #"SYSTEM_SYSRULES_documentImage"(
                          document: fv!item.image
                        )
                      )
                    )
                  )
                }
              )
            }
          ),

          /*Screen: LIVE TV Selection*/
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: and(
              local!activeScreen = "LIVE",
              a!isNullOrEmpty(local!selectedLivestream)
            ),
            width: "3X",
            contents: {
              #"SYSTEM_SYSRULES_cardLayout"(
                marginAbove: "EVEN_MORE",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                shape: "ROUNDED",
                padding: "NONE",
                /*Only the ARD stream works embedded*/
                link: #"SYSTEM_SYSRULES_dynamicLink"(
                  value: "ARD",
                  saveInto: local!selectedLivestream
                ),
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: index(local!livestreams.image, 1, null)
                  )
                )
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: and(
              local!activeScreen = "LIVE",
              a!isNullOrEmpty(local!selectedLivestream)
            ),
            width: "3X",
            contents: {
              #"SYSTEM_SYSRULES_cardLayout"(
                marginAbove: "EVEN_MORE",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                shape: "ROUNDED",
                padding: "NONE",
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: index(local!livestreams.image, 2, null)
                  )
                )
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: and(
              local!activeScreen = "LIVE",
              a!isNullOrEmpty(local!selectedLivestream)
            ),
            width: "3X",
            contents: {
              #"SYSTEM_SYSRULES_cardLayout"(
                marginAbove: "EVEN_MORE",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                shape: "ROUNDED",
                padding: "NONE",
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: index(local!livestreams.image, 3, null)
                  )
                )
              )
            }
          ),

          /*Screen: Embedded Live Stream*/
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: and(
              local!activeScreen = "LIVE",
              a!isNotNullOrEmpty(local!selectedLivestream)
            ),
            width: "10X",
            contents: {
              #"SYSTEM_SYSRULES_webContentField_v1"(
                source: index(
                  local!livestreams.url,
                  wherecontains(local!selectedLivestream, local!livestreams.name),
                  null
                ),
                height: "TALL"
              )
            }
          ),

          /*Screen: VIDEOTHEK / TV SHOWS*/
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: local!activeScreen = "SHOWS",
            width: "3X",
            contents: #"SYSTEM_SYSRULES_forEach"(
              items: index(local!tvShows, {1,2,3,4}, null),
              expression: #"SYSTEM_SYSRULES_cardLayout"(
                marginBelow: "LESS",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                height: "AUTO",
                shape: "ROUNDED",
                padding: "NONE",
                link: #"SYSTEM_SYSRULES_dynamicLink"(),
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: fv!item.image
                  )
                )
              )
            )
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: local!activeScreen = "SHOWS",
            width: "3X",
            contents: #"SYSTEM_SYSRULES_forEach"(
              items: index(local!tvShows, {8,6,7,12}, null),
              expression: #"SYSTEM_SYSRULES_cardLayout"(
                marginBelow: "LESS",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                shape: "ROUNDED",
                padding: "NONE",
                link: #"SYSTEM_SYSRULES_dynamicLink"(),
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: fv!item.image
                  )
                )
              )
            )
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            showWhen: local!activeScreen = "SHOWS",
            width: "3X",
            contents: #"SYSTEM_SYSRULES_forEach"(
              items: index(local!tvShows, {9,10,11,5}, null),
              expression: #"SYSTEM_SYSRULES_cardLayout"(
                marginBelow: "LESS",
                style: "TRANSPARENT",
                showBorder: false,
                showShadow: false,
                shape: "ROUNDED",
                padding: "NONE",
                link: #"SYSTEM_SYSRULES_dynamicLink"(),
                contents: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  size: "FIT",
                  align: "CENTER",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: fv!item.image
                  )
                )
              )
            )
          ),

          /*Empty Padding column on the right*/
          #"SYSTEM_SYSRULES_columnLayout"(
            width: "1X",
            contents: {
              /*a!richTextDisplayField(*/
                /*align: "RIGHT",*/
                /*value: a!richTextItem(*/
                  /*color: cons!PS_COLORS[1],*/
                  /*style: "STRONG",*/
                  /*size: "MEDIUM",*/
                  /*text: hour(local(local!currentTime, "CET"))*/
                  /*& ":"*/
                  /*& text(minute(local!currentTime), "00")*/
                  /*& "   "*/
                /*)*/
              /*)*/
            }
          )
        }
      )
    },
    backgroundColor: "#111111",
    contentsPadding: "NONE"
  )
)
